// Client registration endpoint (admin only)
app.post('/clients', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens[token];

  if (!tokenData || tokenData.expires_at < Date.now()) {
    return res.status(401).json({ error: 'Invalid or expired token' });
  }

  if (!tokenData.user.roles.includes('admin')) {
    return res.status(403).json({ error: 'Admin role required' });
  }

  const { client_id, client_name, redirect_uris } = req.body;

  if (!client_id || !client_name || !redirect_uris || !Array.isArray(redirect_uris)) {
    return res.status(400).json({ error: 'client_id, client_name, and redirect_uris (array) are required' });
  }

  if (registeredClients[client_id]) {
    return res.status(409).json({ error: 'Client already exists' });
  }

  const client_secret = crypto.randomBytes(32).toString('hex');

  registeredClients[client_id] = {
    client_id,
    client_secret,
    redirect_uris,
    name: client_name
  };

  res.status(201).json({
    client_id,
    client_secret,
    client_name,
    redirect_uris
  });
});

